// ══════════════════════════════════════════════════════════════
//  ЭКРАН СЧЁТА eTOLL (нативный UI вместо страницы Details на сайте).
//  Кнопки ведут в WebView только на нужный URL: top-up или смена карты.
//  Cred+Bal и цепочка баланса не затрагиваются.
// ══════════════════════════════════════════════════════════════
class TopUpAccountScreen extends StatefulWidget {
  final String login;
  final String subjectId;
  final String language;
  const TopUpAccountScreen({
    super.key,
    required this.login,
    this.subjectId = '',
    this.language = 'ru',
  });
  @override
  State<TopUpAccountScreen> createState() => _TopUpAccountScreenState();
}

class _TopUpAccountScreenState extends State<TopUpAccountScreen> {
  String _balance = '—';
  String _company = '';
  String _accountId = '';
  String _subjectId = '';
  String _card4 = '';
  bool _autoTopUp = false;
  String _autoMin = '50';
  String _autoFill = '100';
  String _finTypeStored = '';

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<void> _load() async {
    final bal = await BalanceStore.lastBalance();
    final company = await BalanceStore.company();
    final aid = await BalanceStore.accountId();
    final sid = await BalanceStore.subjectId();
    final card4 = await BalanceStore.topUpCard4();
    final auto = await BalanceStore.autoTopUp();
    final autoMin = await BalanceStore.autoTopMin();
    final autoFill = await BalanceStore.autoTopFill();
    final finType = await BalanceStore.finType();
    if (!mounted) return;
    setState(() {
      _balance = (bal != null && bal.isNotEmpty) ? bal : '—';
      _company = company ?? '';
      _accountId = aid ?? '';
      _subjectId = widget.subjectId.trim().isNotEmpty
          ? widget.subjectId.trim()
          : (sid ?? '');
      _card4 = card4;
      _autoTopUp = auto;
      _autoMin = autoMin;
      _autoFill = autoFill;
      _finTypeStored = finType;
    });
  }

  String get _typeLabel {
    if (_finTypeStored.isNotEmpty) return _finTypeStored;
    return _autoTopUp
        ? AppStrings.tr(gAppLang, 'fin_type_auto')
        : AppStrings.tr(gAppLang, 'fin_type_prepay');
  }

  void _openWeb(String directAction) {
    Navigator.of(context).push(
      MaterialPageRoute(
        builder: (_) => TopUpWebScreen(
          title: directAction == 'changeCard'
              ? AppStrings.tr(gAppLang, 'change_card')
              : AppStrings.tr(gAppLang, 'etoll_topup'),
          login: widget.login,
          subjectId: _subjectId,
          accountId: _accountId,
          directAction: directAction,
          language: widget.language,
        ),
      ),
    ).then((_) => _load());
  }

  Widget _row(String label, String value, {Color? valueColor}) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 6),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          SizedBox(
            width: 130,
            child: Text(label,
                style: const TextStyle(
                    color: AppColors.textSecondary, fontSize: 14)),
          ),
          Expanded(
            child: Text(value,
                style: TextStyle(
                    color: valueColor ?? AppColors.textPrimary,
                    fontSize: 15,
                    fontWeight: FontWeight.w600)),
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    const balanceGreen = Color(0xFF34C77B);
    const etRed = Color(0xFFE2231A);
    return Scaffold(
      backgroundColor: AppColors.background,
      appBar: AppBar(
        backgroundColor: AppColors.background,
        elevation: 0,
        iconTheme: const IconThemeData(color: AppColors.accent),
        title: Text(AppStrings.tr(gAppLang, 'etoll_topup'),
            style: const TextStyle(
                color: AppColors.textPrimary, fontSize: 18)),
        actions: [
          IconButton(
            tooltip: AppStrings.tr(gAppLang, 'to_home'),
            icon: const Icon(Icons.home_rounded, color: AppColors.accent),
            onPressed: () =>
                Navigator.of(context).popUntil((r) => r.isFirst),
          ),
        ],
      ),
      body: ListView(
        padding: const EdgeInsets.fromLTRB(20, 8, 20, 24),
        children: [
          if (_company.isNotEmpty)
            Text(_company,
                style: const TextStyle(
                    color: AppColors.textSecondary, fontSize: 13)),
          if (_accountId.isNotEmpty)
            Text('${AppStrings.tr(gAppLang, 'account_id')}: $_accountId',
                style: const TextStyle(
                    color: AppColors.textMuted, fontSize: 12)),
          const SizedBox(height: 16),
          Container(
            padding: const EdgeInsets.all(16),
            decoration: BoxDecoration(
              color: AppColors.surfaceRaised,
              borderRadius: BorderRadius.circular(12),
              border: Border.all(
                  color: AppColors.textMuted.withValues(alpha: 0.25)),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                _row(AppStrings.tr(gAppLang, 'type_lbl'), _typeLabel),
                _row(AppStrings.tr(gAppLang, 'balance_etoll'), _balance,
                    valueColor: balanceGreen),
                if (_autoTopUp) ...[
                  _row(AppStrings.tr(gAppLang, 'topup_below'),
                      '$_autoMin PLN'),
                  _row(AppStrings.tr(gAppLang, 'topup_fill_amt'),
                      '$_autoFill PLN'),
                ],
                const SizedBox(height: 8),
                Row(
                  children: [
                    const Icon(Icons.credit_card,
                        color: AppColors.textSecondary, size: 20),
                    const SizedBox(width: 8),
                    Expanded(
                      child: Text(
                        _card4.isNotEmpty
                            ? AppStrings.tr(gAppLang, 'card_masked')
                                .replaceAll('{0}', _card4)
                            : AppStrings.tr(gAppLang, 'card_not_linked'),
                        style: const TextStyle(
                            color: AppColors.textPrimary, fontSize: 14),
                      ),
                    ),
                    TextButton(
                      onPressed: () => _openWeb('changeCard'),
                      child: Text(AppStrings.tr(gAppLang, 'change_card'),
                          style: const TextStyle(color: AppColors.accent)),
                    ),
                  ],
                ),
              ],
            ),
          ),
          const SizedBox(height: 20),
          OutlinedButton(
            onPressed: () => _openWeb('topUp'),
            style: OutlinedButton.styleFrom(
              foregroundColor: AppColors.accent,
              side: const BorderSide(color: AppColors.accent, width: 1.5),
              padding: const EdgeInsets.symmetric(vertical: 14),
              shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(10)),
            ),
            child: Text(
              AppStrings.tr(gAppLang, 'topup_account_btn'),
              style: const TextStyle(
                  fontSize: 16, fontWeight: FontWeight.w700),
            ),
          ),
          const SizedBox(height: 12),
          SwitchListTile(
            contentPadding: EdgeInsets.zero,
            title: Text(AppStrings.tr(gAppLang, 'autopay'),
                style: const TextStyle(
                    color: AppColors.textPrimary,
                    fontWeight: FontWeight.w600)),
            value: _autoTopUp,
            activeColor: etRed,
            onChanged: (v) async {
              await BalanceStore.setAutoTopUp(v);
              if (mounted) setState(() => _autoTopUp = v);
            },
          ),
          Text(
            AppStrings.tr(gAppLang, 'etoll_link_note') +
                AppStrings.tr(gAppLang, 'etoll_link_next'),
            style: TextStyle(color: AppColors.textMuted, fontSize: 11),
          ),
        ],
      ),
    );
  }
}

