Future<String> _grabAccountId(InAppWebViewController c) async {
  final r = await c.evaluateJavascript(source: r'''
    (function(){try{
      // 1) прямые ссылки на prepaid
      var a=document.querySelectorAll('a[href*="/financing/prepaid/"]');
      for(var i=0;i<a.length;i++){
        var m=(a[i].getAttribute('href')||'').match(/prepaid\/(\d+)/);
        if(m) return m[1];
      }
      // 2) любые ссылки с financing/<id>
      var b=document.querySelectorAll('a[href*="/financing/"]');
      for(var i=0;i<b.length;i++){
        var m=(b[i].getAttribute('href')||'').match(/financing\/(?:prepaid\/)?(\d+)/);
        if(m) return m[1];
      }
      // 3) поиск в HTML
      var m2=document.body.innerHTML.match(/prepaid\/(\d+)/);
      if(m2) return m2[1];
      // 4) financing/list: ID в тексте (напр. 1000434)
      var body=document.body.innerText||'';
      var prepWords=['prepayment','przedpłat','przedplat','prepaid','automatyczne','automatic'];
      var lines=body.split('\n');
      for(var i=0;i<lines.length;i++){
        var ln=lines[i].trim();
        if(!ln) continue;
        var idOnly=ln.match(/^(\d{6,8})$/);
        if(idOnly) return idOnly[1];
        var low=ln.toLowerCase();
        for(var w=0;w<prepWords.length;w++){
          if(low.indexOf(prepWords[w])>=0){
            var block=(lines[i-1]||'')+' '+ln+' '+(lines[i+1]||'');
            var m3=block.match(/(\d{6,8})/);
            if(m3) return m3[1];
          }
        }
      }
      var near=body.match(/(\d{6,8})[\s\S]{0,120}(?:PLN|Prepayment|Przedpłat|Przedplat)/i);
      if(near) return near[1];
      var near2=body.match(/(?:Prepayment|Przedpłat|Przedplat)[\s\S]{0,120}(\d{6,8})/i);
      if(near2) return near2[1];
      return '';
    }catch(e){return '';}})();
  ''');
  return (r ?? '').toString().trim();
}

// Достать prepaid ID: текущая страница → financing/list (с повторами).
Future<String> _fetchPrepaidAccountId(
    InAppWebViewController c, String subjectId) async {
  for (int r = 0; r < 4; r++) {
    final id = await _grabAccountId(c);
    if (id.isNotEmpty) return id;
    await Future.delayed(const Duration(milliseconds: 800));
  }
  if (subjectId.isEmpty) return '';
  final urls = [
    'https://mojekonto.etoll.gov.pl/selfservice/#/mobile/subject/$subjectId/manage/financing/list',
    'https://mojekonto.etoll.gov.pl/selfservice/#/mobile/subject/$subjectId/financing/list',
  ];
  for (final url in urls) {
    try {
      await c.loadUrl(urlRequest: URLRequest(url: WebUri(url)));
    } catch (_) {}
    await Future.delayed(const Duration(milliseconds: 2200));
    for (int r = 0; r < 5; r++) {
      final id = await _grabAccountId(c);
      if (id.isNotEmpty) return id;
      await Future.delayed(const Duration(milliseconds: 900));
    }
  }
  return '';
}

