String _financingListUrl([String? sidOverride]) {
  final sid = (sidOverride ?? _sid).trim();
  if (sid.isEmpty) return _startUrl;
  return 'https://mojekonto.etoll.gov.pl/selfservice/#/mobile/subject/$sid/manage/financing/list';
}

String get _initialUrl {
  final sid = widget.subjectId.trim();
  final aid = widget.accountId.trim();
  // Прямой deep-link на top-up/details часто сбрасывается на list/manage.
  // Надёжнее: список финансов → Details → кнопка на странице details.
  if (widget.directAction.isNotEmpty && sid.isNotEmpty && aid.isNotEmpty) {
    return _financingListUrl(sid);
  }
  return _startUrl;
}

Future<void> _navigateHash(String hash) async {
  if (_controller == null || hash.isEmpty) return;
  final h = hash.startsWith('/') ? hash : '/$hash';
  final esc = h.replaceAll("'", "\\'").replaceAll(r'\', r'\\');
  await _controller!.evaluateJavascript(source: '''
    (function(){
      try {
        var h = '$esc';
        var base = '/selfservice';
        if (window.history && window.history.pushState) {
          window.history.pushState(null, '', base + '#' + h);
          window.dispatchEvent(new PopStateEvent('popstate', {state: null}));
        }
        window.location.hash = h;
        try {
          window.dispatchEvent(new HashChangeEvent('hashchange'));
        } catch(e) {}
      } catch(e) { try { window.location.hash = '$esc'; } catch(e2) {} }
    })();
  ''');
  await Future.delayed(const Duration(milliseconds: 550));
}

Future<void> _goPrepaid(String suffix) async {
  final sid = _sid;
  final aid = _aid;
  if (sid.isEmpty || aid.isEmpty || _controller == null) return;
  final hash = '/mobile/subject/$sid/financing/prepaid/$aid/$suffix';
  await _navigateHash(hash);
  if (_stepTicks <= 1 || _stepTicks % 4 == 0) {
    try {
      await _controller!.loadUrl(
        urlRequest: URLRequest(
          url: WebUri(_prepaidPath(suffix)),
          headers: _etollEnHeaders,
        ),
      );
    } catch (_) {}
  }
}

Future<void> _goFinancingList() async {
  final sid = _sid;
  if (sid.isEmpty || _controller == null) return;
  await _navigateHash('/mobile/subject/$sid/manage/financing/list');
  if (_stepTicks <= 1 || _stepTicks % 4 == 0) {
    try {
      await _controller!.loadUrl(
        urlRequest: URLRequest(
          url: WebUri(_financingListUrl(sid)),
          headers: _etollEnHeaders,
        ),
      );
    } catch (_) {}
  }
}

