# Backup Cursor chat history to Dropbox
# Run: BEKAP_CHATOV.bat or auto on sessionEnd (hook)

param(
    [switch]$Quiet,
    [switch]$Snapshot
)

$ErrorActionPreference = 'SilentlyContinue'
$BackupRoot = Split-Path -Parent $MyInvocation.MyCommand.Path
$Latest = Join-Path $BackupRoot 'latest'
$LogFile = Join-Path $BackupRoot 'backup.log'
$DebounceFile = Join-Path $BackupRoot '.last-backup.txt'
$DebounceMinutes = 10

function Write-Log([string]$Msg) {
    $line = "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')  $Msg"
    Add-Content -LiteralPath $LogFile -Value $line -Encoding UTF8
    if (-not $Quiet) { Write-Host $line }
}

if (-not (Test-Path -LiteralPath $BackupRoot)) {
    New-Item -ItemType Directory -Path $BackupRoot -Force | Out-Null
}

if ($Quiet -and -not $Snapshot -and (Test-Path -LiteralPath $DebounceFile)) {
    $last = Get-Content -LiteralPath $DebounceFile -ErrorAction SilentlyContinue | Select-Object -First 1
    if ($last) {
        try {
            $t = [datetime]::ParseExact($last.Trim(), 'yyyy-MM-dd HH:mm:ss', $null)
            if (((Get-Date) - $t).TotalMinutes -lt $DebounceMinutes) { exit 0 }
        } catch {}
    }
}

Write-Log '=== backup start ==='

$projectsRoot = Join-Path $env:USERPROFILE '.cursor\projects'
$transcriptsDst = Join-Path $Latest 'agent-transcripts'
$storageSrc = Join-Path $env:APPDATA 'Cursor\User\workspaceStorage'
$storageDst = Join-Path $Latest 'workspaceStorage'
$plansSrc = Join-Path $env:USERPROFILE '.cursor\plans'
$plansDst = Join-Path $Latest 'plans'
$projectCursorSrc = 'C:\projects\.cursor'
$projectCursorDst = Join-Path $Latest 'projects-cursor'

if (Test-Path -LiteralPath $Latest) {
    Remove-Item -LiteralPath $Latest -Recurse -Force
}
New-Item -ItemType Directory -Path $Latest -Force | Out-Null
New-Item -ItemType Directory -Path $transcriptsDst -Force | Out-Null
New-Item -ItemType Directory -Path $storageDst -Force | Out-Null

$chatCount = 0
if (Test-Path -LiteralPath $projectsRoot) {
    Get-ChildItem -LiteralPath $projectsRoot -Directory | ForEach-Object {
        $src = Join-Path $_.FullName 'agent-transcripts'
        if (-not (Test-Path -LiteralPath $src)) { return }
        $dst = Join-Path $transcriptsDst $_.Name
        robocopy $src $dst /E /R:1 /W:1 /NFL /NDL /NJH /NJS | Out-Null
        $chatCount += @(Get-ChildItem -LiteralPath $src -Recurse -Filter '*.jsonl' -File).Count
    }
}

if (Test-Path -LiteralPath $storageSrc) {
    robocopy $storageSrc $storageDst /E /R:1 /W:1 /NFL /NDL /NJH /NJS | Out-Null
}

if (Test-Path -LiteralPath $plansSrc) {
    New-Item -ItemType Directory -Path $plansDst -Force | Out-Null
    robocopy $plansSrc $plansDst /E /R:1 /W:1 /NFL /NDL /NJH /NJS | Out-Null
}

if (Test-Path -LiteralPath $projectCursorSrc) {
    New-Item -ItemType Directory -Path $projectCursorDst -Force | Out-Null
    robocopy $projectCursorSrc $projectCursorDst /E /R:1 /W:1 /NFL /NDL /NJH /NJS | Out-Null
}

$pc = $env:COMPUTERNAME
$info = @(
    'Cursor chat backup'
    "PC: $pc"
    "User: $env:USERNAME"
    "Time: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
    "Chats (.jsonl): $chatCount"
    "Source transcripts: $projectsRoot"
    "Source workspaceStorage: $storageSrc"
    ''
    'Restore on new PC: run VOSSTANOVIT_CHATY.bat from this folder'
)
$info | Set-Content -LiteralPath (Join-Path $Latest 'BACKUP_INFO.txt') -Encoding UTF8

if ($Snapshot -or -not $Quiet) {
    $stamp = Get-Date -Format 'yyyy-MM-dd_HH-mm'
    $snapDir = Join-Path $BackupRoot "cursor_history_$stamp"
    robocopy $Latest $snapDir /E /NFL /NDL /NJH /NJS | Out-Null
    Write-Log "snapshot: $snapDir"
}

Get-Date -Format 'yyyy-MM-dd HH:mm:ss' | Set-Content -LiteralPath $DebounceFile -Encoding ASCII
Write-Log "done. chats: $chatCount -> $Latest"

if (-not $Quiet) {
    Write-Host ''
    Write-Host 'Backup ready in Dropbox.' -ForegroundColor Green
    Write-Host $Latest
    Read-Host 'Press Enter to close'
}

exit 0

