import 'dart:io';

void main() {
  final content = File('lib/main.dart').readAsStringSync();
  const langs = ['ru', 'ro', 'en', 'pl', 'de', 'fr', 'it', 'es', 'bg', 'uk'];
  final langKeys = <String, Set<String>>{};

  for (final lang in langs) {
    final marker = "'$lang': {";
    final start = content.indexOf(marker);
    if (start < 0) {
      print('MISSING LANG BLOCK: $lang');
      continue;
    }
    var depth = 0;
    var i = content.indexOf('{', start);
    final begin = i;
    for (; i < content.length; i++) {
      final c = content[i];
      if (c == '{') depth++;
      if (c == '}') {
        depth--;
        if (depth == 0) break;
      }
    }
    final block = content.substring(begin + 1, i);
    final keys = RegExp(r"'([^']+)'\s*:")
        .allMatches(block)
        .map((m) => m.group(1)!)
        .toSet();
    langKeys[lang] = keys;
  }

  final ru = langKeys['ru']!;
  print('RU keys: ${ru.length}');
  for (final lang in langs) {
    if (lang == 'ru') continue;
    final keys = langKeys[lang] ?? {};
    final missing = ru.difference(keys).toList()..sort();
    final extra = keys.difference(ru).toList()..sort();
    print('\n=== $lang: missing ${missing.length}, extra ${extra.length} ===');
    for (final k in missing) {
      print('  - $k');
    }
  }
}

