import 'package:flutter/material.dart';

/// Связка main → блоки: AppDrawer живёт в main.dart, блоки получают drawer через регистрацию.
typedef AppDrawerBuilder = Widget Function(String language);

AppDrawerBuilder? _appDrawerBuilder;

void registerAppDrawerBuilder(AppDrawerBuilder builder) {
  _appDrawerBuilder = builder;
}

Widget? appDrawerFor(String language) => _appDrawerBuilder?.call(language);

import 'package:flutter/material.dart';

import 'nav_forward.dart';

/// Шапка: [≡] [←] заголовок [→] … [дом].
class RcNavAppBar extends StatelessWidget implements PreferredSizeWidget {
  const RcNavAppBar({
    super.key,
    required this.title,
    required this.accentColor,
    this.backgroundColor,
    this.textColor = const Color(0xFFE8EEF8),
    this.bottom,
    this.backTooltip,
    this.forwardTooltip,
    this.homeTooltip,
    this.menuTooltip,
    this.showBack = true,
    this.showForward = true,
    this.showHome = true,
    this.showMenu = true,
    this.extraActions = const [],
    this.onMenuTap,
  });

  final String title;
  final Color accentColor;
  final Color? backgroundColor;
  final Color textColor;
  final PreferredSizeWidget? bottom;
  final String? backTooltip;
  final String? forwardTooltip;
  final String? homeTooltip;
  final String? menuTooltip;
  final bool showBack;
  final bool showForward;
  final bool showHome;
  final bool showMenu;
  final List<Widget> extraActions;
  final VoidCallback? onMenuTap;

  @override
  Size get preferredSize =>
      Size.fromHeight(kToolbarHeight + (bottom?.preferredSize.height ?? 0));

  void _openMenu(BuildContext context) {
    if (onMenuTap != null) {
      onMenuTap!();
      return;
    }
    final scaffold = Scaffold.maybeOf(context);
    if (scaffold?.hasDrawer ?? false) {
      scaffold!.openDrawer();
    }
  }

  Widget _menuButton(BuildContext context) {
    return IconButton(
      tooltip: menuTooltip,
      padding: EdgeInsets.zero,
      constraints: const BoxConstraints(minWidth: 44, minHeight: 44),
      icon: Container(
        width: 36,
        height: 36,
        decoration: BoxDecoration(
          color: accentColor.withValues(alpha: 0.1),
          borderRadius: BorderRadius.circular(10),
          border: Border.all(color: accentColor.withValues(alpha: 0.38)),
        ),
        child: Icon(Icons.menu_rounded, color: accentColor, size: 22),
      ),
      onPressed: () => _openMenu(context),
    );
  }

  Widget? _buildLeading(BuildContext context) {
    if (showMenu && showBack) {
      return Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          _menuButton(context),
          IconButton(
            tooltip: backTooltip,
            padding: EdgeInsets.zero,
            constraints: const BoxConstraints(minWidth: 44, minHeight: 44),
            icon: Icon(Icons.arrow_back_ios_new_rounded,
                size: 20, color: accentColor),
            onPressed: () => Navigator.maybePop(context),
          ),
        ],
      );
    }
    if (showMenu) return _menuButton(context);
    if (showBack) {
      return IconButton(
        tooltip: backTooltip,
        icon: Icon(Icons.arrow_back_ios_new_rounded,
            size: 20, color: accentColor),
        onPressed: () => Navigator.maybePop(context),
      );
    }
    return null;
  }

  double? get _leadingWidth {
    if (!showMenu && !showBack) return null;
    if (showMenu && showBack) return 96;
    return 56;
  }

  @override
  Widget build(BuildContext context) {
    final actions = <Widget>[
      if (showForward)
        ValueListenableBuilder<bool>(
          valueListenable: NavForward.canForward,
          builder: (_, can, __) {
            final dim = accentColor.withValues(alpha: 0.35);
            return IconButton(
              tooltip: forwardTooltip,
              icon: Icon(Icons.arrow_forward_ios_rounded,
                  size: 20, color: can ? accentColor : dim),
              onPressed: can ? () => NavForward.go(context) : null,
            );
          },
        ),
      ...extraActions,
      if (showHome)
        IconButton(
          tooltip: homeTooltip,
          icon: Icon(Icons.home_rounded, color: accentColor),
          onPressed: () =>
              Navigator.of(context).popUntil((route) => route.isFirst),
        ),
    ];

    return AppBar(
      automaticallyImplyLeading: false,
      backgroundColor: backgroundColor,
      elevation: 0,
      bottom: bottom,
      leadingWidth: _leadingWidth,
      leading: _buildLeading(context),
      title: Text(
        title,
        style: TextStyle(
          color: textColor,
          fontSize: 18,
          fontWeight: FontWeight.w700,
        ),
      ),
      actions: actions,
    );
  }
}

